+import type { Order } from '../../src/models/order.js';
+
+/**
+ * Integration tests for the full notification pipeline:
+ * EventBus → NotificationService → PreferencesService (check) → Adapters (deliver) → HistoryService (log)
+ */
+
+// --- Test fixtures ---
+
+function makeUser(overrides: Partial<User> = {}): User {
+  return {
+    id: 'user-1',
+    name: 'Alice',
+    email: 'alice@example.com',
+    role: 'member',
+    createdAt: new Date(),
+    updatedAt: new Date(),
+    ...overrides,
+  };
+}
+
+function makeOrder(overrides: Partial<Order> = {}): Order {
+  return {
+    id: 'order-1',
+    userId: 'user-1',
+    items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
+    total: 20,
+    status: 'pending',
+    createdAt: new Date(),
+    updatedAt: new Date(),
+    ...overrides,
+  };
+}
+
+describe('Notification Pipeline Integration', () => {
+  let eventBus: EventBus;
+  let preferencesService: PreferencesService;
+  let historyService: NotificationHistoryService;
+  let notificationService: NotificationService;
+
+  let emailTransport: InMemoryEmailTransport;
+  let smsTransport: InMemorySmsTransport;
+  let webhookTransport: InMemoryWebhookTransport;
+
+  let emailAdapter: EmailNotificationAdapter;
+  let smsAdapter: SmsNotificationAdapter;
+  let webhookAdapter: WebhookNotificationAdapter;
+
+  beforeEach(() => {
+    resetNotificationIdCounter();
+    resetLogIdCounter();
+
+    eventBus = new EventBus();
+    preferencesService = new PreferencesService();
+    historyService = new NotificationHistoryService();
+
+    notificationService = new NotificationService(eventBus, preferencesService, historyService);
+
+    emailTransport = new InMemoryEmailTransport();
+    emailAdapter = new EmailNotificationAdapter({ from: 'noreply@taskflow.test' }, emailTransport);
+
+    smsTransport = new InMemorySmsTransport();
+    smsAdapter = new SmsNotificationAdapter({ from: '+10000000000' }, smsTransport);
+
+    webhookTransport = new InMemoryWebhookTransport();
+    webhookAdapter = new WebhookNotificationAdapter({}, webhookTransport);
+
+    notificationService.registerAdapter(emailAdapter);
+    notificationService.registerAdapter(smsAdapter);
+    notificationService.registerAdapter(webhookAdapter);
+  });
+
+  // --- Email channel tests ---
+
+  describe('email notification delivery', () => {
+    it('should deliver email when user has email preferences enabled', async () => {
+      const user = makeUser();
+      const order = makeOrder();
+
+      await eventBus.emit<OrderCreatedEvent>({
+        type: 'order:created',
+        order,
+        user,
+        timestamp: new Date(),
+      });
+
+      // Email adapter received the notification
+      const sentEmails = emailTransport.getSentEmails();
+      expect(sentEmails).toHaveLength(1);
+      expect(sentEmails[0]!.to).toBe('alice@example.com');
+      expect(sentEmails[0]!.subject).toContain('Order Confirmation');
+
+      // Notification service recorded it
+      const notifications = notificationService.getNotifications();
+      expect(notifications).toHaveLength(1);
+      expect(notifications[0]!.channel).toBe('email');
+
+      // Adapter result is success
+      const results = notificationService.getResults();
+      expect(results).toHaveLength(1);
+      expect(results[0]!.success).toBe(true);
+    });
+
+    it('should render correct email content for welcome notification', async () => {
+      const user = makeUser();
+
+      await eventBus.emit<UserCreatedEvent>({
+        type: 'user:created',
+        user,
+        timestamp: new Date(),
+      });
+
+      const sentEmails = emailTransport.getSentEmails();
+      expect(sentEmails).toHaveLength(1);
+      expect(sentEmails[0]!.to).toBe('alice@example.com');
+      expect(sentEmails[0]!.subject).toContain('Welcome');
+      expect(sentEmails[0]!.html).toContain('Welcome to TaskFlow Pro');
+      expect(sentEmails[0]!.text).toContain('Alice');
+    });
+  });
+
+  // --- SMS channel tests ---
+
+  describe('SMS notification delivery', () => {
+    it('should deliver SMS when event targets sms channel and preferences are enabled', async () => {
+      // The built-in handlers send to 'email' channel.
+      // To test SMS delivery end-to-end, we trigger via a direct sendNotification path.
+      // Since sendNotification is private, we use the public event-driven path and
+      // verify that the SMS adapter itself works when registered.
+
+      // The NotificationService event handlers currently only emit email-channel notifications.
+      // But we can verify the SMS adapter is properly integrated by checking that
+      // SMS preferences are respected and the adapter is registered.
+      const prefs = preferencesService.getPreferences('user-1');
+      expect(prefs.sms.enabled).toBe(true);
+
+      // Verify SMS adapter is registered by checking it was accepted
+      expect(smsAdapter.channel).toBe('sms');
+    });
+  });
+
+  // --- Webhook channel tests ---
+
+  describe('webhook notification delivery', () => {
+    it('should have webhook adapter registered and preferences enabled by default', async () => {
+      const prefs = preferencesService.getPreferences('user-1');
+      expect(prefs.webhook.enabled).toBe(true);
+      expect(webhookAdapter.channel).toBe('webhook');
+    });
+  });
+
+  // --- History logging tests ---
+
+  describe('notification history logging', () => {
+    it('should log notification to history after successful email delivery', async () => {
+      const user = makeUser();
+      const order = makeOrder();
+
+      await eventBus.emit<OrderCreatedEvent>({
+        type: 'order:created',
+        order,
+        user,
+        timestamp: new Date(),
+      });
+
+      const logs = historyService.query({});
+      expect(logs).toHaveLength(1);
+      expect(logs[0]!.channel).toBe('email');
+      expect(logs[0]!.type).toBe('order_confirmation');
+      expect(logs[0]!.recipient).toBe('alice@example.com');
+      expect(logs[0]!.status).toBe('delivered');
+      expect(logs[0]!.notificationId).toBe('notif-0001');
+    });
+
+    it('should log multiple notifications in order', async () => {
+      const user = makeUser();
+      const order = makeOrder();
+
+      await eventBus.emit<OrderCreatedEvent>({
+        type: 'order:created',
+        order,
+        user,
+        timestamp: new Date(),
+      });
+
+      await eventBus.emit<OrderStatusChangedEvent>({
+        type: 'order:status-changed',
+        order: { ...order, status: 'confirmed' },
+        user,
+        previousStatus: 'pending',
+        newStatus: 'confirmed',
+        timestamp: new Date(),
+      });
+
+      const logs = historyService.query({});
+      expect(logs).toHaveLength(2);
+      expect(logs[0]!.type).toBe('order_confirmation');
+      expect(logs[1]!.type).toBe('order_status_update');
+      expect(logs[0]!.notificationId).toBe('notif-0001');
+      expect(logs[1]!.notificationId).toBe('notif-0002');
+    });
+
+    it('should log welcome notification in history', async () => {
+      const user = makeUser();
+
+      await eventBus.emit<UserCreatedEvent>({
+        type: 'user:created',
+        user,
+        timestamp: new Date(),
+      });
+
+      const logs = historyService.query({ type: 'welcome' });
+      expect(logs).toHaveLength(1);
+      expect(logs[0]!.recipient).toBe('alice@example.com');
+      expect(logs[0]!.status).toBe('delivered');
+    });
+
+    it('should be queryable by recipient', async () => {
+      const alice = makeUser();
+      const bob = makeUser({ id: 'user-2', name: 'Bob', email: 'bob@example.com' });
+
+      await eventBus.emit<UserCreatedEvent>({
+        type: 'user:created',
+        user: alice,
+        timestamp: new Date(),
+      });
+
+      await eventBus.emit<UserCreatedEvent>({
+        type: 'user:created',
+        user: bob,
+        timestamp: new Date(),
+      });
+
+      const aliceLogs = historyService.getByRecipient('alice@example.com');
+      expect(aliceLogs).toHaveLength(1);
+
+      const bobLogs = historyService.getByRecipient('bob@example.com');
+      expect(bobLogs).toHaveLength(1);
+    });
+  });
+
+  // --- Preferences enforcement tests ---
+
+  describe('user preferences enforcement', () => {
+    it('should suppress email when email channel is disabled', async () => {
+      preferencesService.updatePreferences('user-1', {
+        email: { enabled: false },
+      });
+
+      const user = makeUser();
+      const order = makeOrder();
+
+      await eventBus.emit<OrderCreatedEvent>({
+        type: 'order:created',
+        order,
+        user,
+        timestamp: new Date(),
+      });
+
+      // No email sent
+      expect(emailTransport.getSentEmails()).toHaveLength(0);
+      // No notification recorded
+      expect(notificationService.getNotifications()).toHaveLength(0);
+      // No history entry (suppressed notifications are not logged)
+      expect(historyService.query({})).toHaveLength(0);
+    });
+
+    it('should suppress email when notification type is not in categories', async () => {
+      preferencesService.updatePreferences('user-1', {
+        email: { categories: ['welcome'] },  // only allow welcome, not order_confirmation
+      });
+
+      const user = makeUser();
+      const order = makeOrder();
+
+      await eventBus.emit<OrderCreatedEvent>({
+        type: 'order:created',
+        order,
+        user,
+        timestamp: new Date(),
+      });
+
+      expect(emailTransport.getSentEmails()).toHaveLength(0);
+      expect(notificationService.getNotifications()).toHaveLength(0);
+      expect(historyService.query({})).toHaveLength(0);
+    });
+
+    it('should allow email when user explicitly enables the channel and category', async () => {
+      // Disable then re-enable
+      preferencesService.updatePreferences('user-1', {
+        email: { enabled: false },
+      });
+      preferencesService.updatePreferences('user-1', {
+        email: { enabled: true },
+      });
+
+      const user = makeUser();
+
+      await eventBus.emit<UserCreatedEvent>({
+        type: 'user:created',
+        user,
+        timestamp: new Date(),
+      });
+
+      expect(emailTransport.getSentEmails()).toHaveLength(1);
+      expect(historyService.query({})).toHaveLength(1);
+    });
+
+    it('should suppress specific notification type but allow others', async () => {
+      preferencesService.updatePreferences('user-1', {
+        email: { categories: ['welcome'] },  // only welcome
+      });
+
+      const user = makeUser();
+
+      // This should be suppressed (order_confirmation not in categories)
+      await eventBus.emit<OrderCreatedEvent>({
+        type: 'order:created',
+        order: makeOrder(),
+        user,
+        timestamp: new Date(),
+      });
+
+      // This should be delivered (welcome is in categories)
+      await eventBus.emit<UserCreatedEvent>({
+        type: 'user:created',
+        user,
+        timestamp: new Date(),
+      });
+
+      expect(emailTransport.getSentEmails()).toHaveLength(1);
+      expect(emailTransport.getSentEmails()[0]!.subject).toContain('Welcome');
+
+      const logs = historyService.query({});
+      expect(logs).toHaveLength(1);
+      expect(logs[0]!.type).toBe('welcome');
+    });
+
+    it('should independently control preferences per user', async () => {
+      // Disable email for user-1, leave user-2 with defaults (enabled)
+      preferencesService.updatePreferences('user-1', {
+        email: { enabled: false },
+      });
+
+      const alice = makeUser({ id: 'user-1', email: 'alice@example.com' });
+      const bob = makeUser({ id: 'user-2', email: 'bob@example.com' });
+
+      await eventBus.emit<UserCreatedEvent>({
+        type: 'user:created',
+        user: alice,
+        timestamp: new Date(),
+      });
+
+      await eventBus.emit<UserCreatedEvent>({
+        type: 'user:created',
+        user: bob,
+        timestamp: new Date(),
+      });
+
+      const sentEmails = emailTransport.getSentEmails();
+      expect(sentEmails).toHaveLength(1);
+      expect(sentEmails[0]!.to).toBe('bob@example.com');
+    });
+
+    it('should suppress SMS channel when disabled in preferences', async () => {
+      preferencesService.updatePreferences('user-1', {
+        sms: { enabled: false },
+      });
+
+      const shouldSend = preferencesService.shouldSend('user-1', 'sms', 'order_confirmation');
+      expect(shouldSend).toBe(false);
+    });
+
+    it('should suppress webhook channel when disabled in preferences', async () => {
+      preferencesService.updatePreferences('user-1', {
+        webhook: { enabled: false },
+      });
+
+      const shouldSend = preferencesService.shouldSend('user-1', 'webhook', 'order_confirmation');
+      expect(shouldSend).toBe(false);
+    });
+  });
+
+  // --- Notification ordering tests ---
+
+  describe('notification ordering', () => {
+    it('should deliver notifications for the same user in emission order', async () => {
+      const user = makeUser();
+      const order = makeOrder();
+
+      // Emit order:created followed by order:status-changed
+      await eventBus.emit<OrderCreatedEvent>({
+        type: 'order:created',
+        order,
+        user,
+        timestamp: new Date(),
+      });
+
+      await eventBus.emit<OrderStatusChangedEvent>({
+        type: 'order:status-changed',
+        order: { ...order, status: 'confirmed' },
+        user,
