+
+      const notifications = notificationService.getNotifications();
+      expect(notifications).toHaveLength(2);
+      expect(notifications[0]!.type).toBe('order_confirmation');
+      expect(notifications[1]!.type).toBe('order_status_update');
+
+      // History also in order
+      const logs = historyService.query({});
+      expect(logs).toHaveLength(2);
+      expect(logs[0]!.type).toBe('order_confirmation');
+      expect(logs[1]!.type).toBe('order_status_update');
